#include<bits/stdc++.h>
using namespace std;
const int N=1000010;
int n,m,val[N],top[N],dfn[N],dfncnt,fa[N],siz[N],rnk[N],son[N],d[N],mod;
vector<int> mp[N];
void dfs1(int x,int f=0)
{
    fa[x]=f;
    siz[x]=1;
    son[x]=-1;
    for(int i:mp[x])
    {
        if(i!=f)
        {
            d[i]=d[x]+1;
            dfs1(i,x);
            siz[x]+=siz[i];
            if(son[x]==-1||siz[i]>siz[son[x]])
            {
                son[x]=i;
            }
        }
    }
}
void dfs2(int x,int t)
{
    top[x]=t;
    dfn[x]=++dfncnt;
    rnk[dfncnt]=x;
    if(son[x]!=-1)
    {
        dfs2(son[x],t);
        for(int i:mp[x])
        {
            if(i!=fa[x]&&i!=son[x])
            {
                dfs2(i,i);
            }
        }
    }
}
int lca(int x,int y)
{
    while(top[x]!=top[y])
    {
        if(d[top[x]]<d[top[y]])
        {
            swap(x,y);
        }
        x=fa[top[x]];
    }
    if(dfn[x]>dfn[y])
    {
        swap(x,y);
    }
    return x;
}
int dis(int u,int v)
{
    return d[u]+d[v]-d[lca(u,v)]*2+1;
}
int lowbit(int x)
{
    return x&-x;
}
int s[N];
void add(int x,int v)
{
    for(int i=x;i<=n;i+=lowbit(i))
    {
        s[i]+=v;
    }
}
int query(int x)
{
    int ans=0;
    for(int i=x;i>=1;i-=lowbit(i))
    {
        ans+=s[i];
    }
    return ans;
}
int calc(int x,int y)
{
    int l=lca(x,y);
    return query(dfn[x])+query(dfn[y])-query(dfn[l])-query(dfn[fa[l]]);
}
int op[N],x[N],y[N],ans[N];
vector<int> v[N];
int main()
{
    scanf("%d",&n);
    int r=1;
    for(int i=1;i<=n;i++)
    {
        int x;
        scanf("%d",&x);
        if(x==0)
        {
            r=i;
        }
        mp[x].push_back(i);
    }
    dfs1(r);
    dfs2(r,r);
    scanf("%d",&m);
    for(int i=1;i<=m;i++)
    {
        scanf("%d",&op[i]);
        if(op[i]==1)
        {
            int k;
            scanf("%d%d%d",&x[i],&y[i],&k);
            if(k<i)
            {
                v[i-k-1].push_back(i);
            }
        }
        else
        {
            scanf("%d",&x[i]);
        }
    }
    for(int i=1;i<=m;i++)
    {
        if(op[i]==2)
        {
            add(dfn[x[i]],1);
            add(dfn[x[i]]+siz[x[i]],-1);
        }
        for(int j:v[i])
        {
            ans[j]=calc(x[j],y[j]);
        }
        if(op[i]==1)
        {
            printf("%d %d\n",dis(x[i],y[i]),ans[i]);
        }
    }
    return 0;
}
